/**
 * SafeAjax setup — registers window.webapi.safeAjax for Power Pages.
 *
 * On Power Pages the portal runtime provides jQuery, shell, and
 * validateLoginSession as globals. This module wires them together
 * into a safeAjax function that handles XSRF token acquisition and
 * session validation for Dataverse Web API calls.
 *
 * The setup runs eagerly at module import time AND provides a
 * waitForSafeAjax() async retry loop that polls for jQuery/shell
 * to become available — handling the case where the app bundle
 * loads before the Portal runtime globals are ready.
 */

import type { AjaxSettings, AjaxPromise, SafeAjaxFn } from './types';

/* ─── Register if globals are present ─────────────────── */

function registerSafeAjax(): boolean {
  const jq = window.jQuery;
  const portalShell = window.shell;
  if (!jq || !portalShell) return false;

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const $: any = jq;

  const webapi = ((window as unknown as { webapi?: { safeAjax?: SafeAjaxFn } }).webapi =
    (window as unknown as { webapi?: { safeAjax?: SafeAjaxFn } }).webapi || {});

  function safeAjax(
    ajaxOptions: AjaxSettings,
  ): AjaxPromise {
    const deferredAjax = $.Deferred();

    portalShell.getTokenDeferred().done(function (token: string) {
      if (!ajaxOptions.headers) {
        $.extend(ajaxOptions, {
          headers: {
            __RequestVerificationToken: token,
          },
        });
      } else {
        (ajaxOptions.headers as Record<string, string>)['__RequestVerificationToken'] = token;
      }

      $.ajax(ajaxOptions)
        .done(function (data: unknown, textStatus: string, jqXHR: unknown) {
          validateLoginSession(data, textStatus, jqXHR as { status: number }, function () {
            // Pass the response data through the deferred so dataverseAjax
            // and other promise-based callers receive the API result.
            deferredAjax.resolve(data);
          });
        })
        .fail(function () {
          deferredAjax.reject();
        });
    }).fail(function () {
      deferredAjax.reject();
    });

    return deferredAjax.promise();
  }

  webapi.safeAjax = safeAjax;
  return true;
}

/* ─── Eager attempt at import time ────────────────────── */

registerSafeAjax();

/* ─── Ensure safeAjax is ready (called by data source) ── */

/**
 * Synchronous check — returns true once safeAjax is available.
 * On Power Pages the first call typically succeeds because by the
 * time the data source initializes, the portal shell has loaded.
 */
export function ensureSafeAjax(): boolean {
  if (window.webapi?.safeAjax) return true;
  return registerSafeAjax();
}

/**
 * Wait for safeAjax to become available with polling retries.
 *
 * On Power Pages, jQuery and shell are provided by the portal runtime
 * and may not be available when the app bundle first executes.
 * This function polls until they appear or the timeout expires.
 *
 * @param timeoutMs  Max time to wait (default 15 seconds)
 * @param intervalMs Poll interval (default 200ms)
 */
export async function waitForSafeAjax(
  timeoutMs = 15_000,
  intervalMs = 200,
): Promise<boolean> {
  // Fast path — already registered
  if (window.webapi?.safeAjax) return true;

  // Poll until timeout
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    await new Promise((r) => setTimeout(r, intervalMs));
    if (window.webapi?.safeAjax) return true;
    if (registerSafeAjax()) return true;
  }

  return false;
}
