/* ─── Inquiry Status (vpi_status on vpi_vehicleinquiries) ─ */
export const inquiryStatusMapping: Record<string, number> = {
  Pending: 1,
  Reviewed: 2,
  Contacted: 3,
  Closed: 4,
};

export const inquiryStatusLabels = Object.keys(inquiryStatusMapping);

/** Reverse lookup: numeric Dataverse value → status label */
export function inquiryStatusLabel(value: number): string {
  for (const [label, num] of Object.entries(inquiryStatusMapping)) {
    if (num === value) return label;
  }
  return 'Pending';
}

/* ─── Year (vpi_year) — stored as text, parsed to number ─ */

/**
 * Normalise a formatted option set value against the canonical labels.
 * Returns the matched canonical label, or the fallback if no match found.
 */
export function normaliseOptionSet(
  formattedValue: string | null | undefined,
  validLabels: readonly string[],
  fallback: string,
): string {
  if (!formattedValue) return fallback;
  const trimmed = formattedValue.trim();
  const match = validLabels.find(
    (v) => v.toLowerCase() === trimmed.toLowerCase(),
  );
  return match ?? fallback;
}
