/**
 * Typed promise wrapper around window.webapi.safeAjax.
 */

import type { AjaxSettings } from './types';
import { waitForSafeAjax } from './safeAjaxLoader';

/**
 * Invoke the Dataverse Web API via the portal's safeAjax wrapper.
 *
 * Reads `window.webapi.safeAjax` which is registered by safeAjaxLoader.ts.
 * Awaits safeAjax availability with a retry loop (15s timeout) so that
 * the Portal runtime (jQuery + shell) has time to initialise.
 *
 * Returns a typed promise for convenience.
 *
 * @example
 *   const vehicles = await dataverseAjax({ type: 'GET', url: '/_api/vpi_vehicledatas' });
 */
export async function dataverseAjax<T = unknown>(
  options: AjaxSettings,
): Promise<T> {
  const ready = await waitForSafeAjax();
  if (!ready) {
    return Promise.reject(
      new Error(
        'safeAjax not available after 15s timeout. Ensure the Power Pages portal runtime (jQuery + shell) is loaded.',
      ),
    );
  }

  return new Promise<T>((resolve, reject) => {
    const promise = window.webapi!.safeAjax(options);
    promise.done((data: unknown) => resolve(data as T));
    promise.fail((...args: unknown[]) => reject(args));
  });
}
