/**
 * Inquiry Service — Dataverse persistence for contacts and vehicle inquiries.
 *
 * Handles:
 *   1. Contact lookup by email / creation
 *   2. Vehicle inquiry creation (linked to contact + vehicle)
 *   3. Inquiry retrieval with expanded contact + vehicle data
 *   4. Inquiry status updates
 *
 * @see https://learn.microsoft.com/en-us/power-pages/configure/web-api-odata
 */

import type { Inquiry, InquiryStatus } from '@types';
import { dataverseAjax } from './dataverseAjax';
import { cityMapping, inquiryStatusMapping, inquiryStatusLabel } from './optionSetMappings';

/* ─── Types ──────────────────────────────────────────── */

interface DataverseContactRow {
  contactid: string;
  firstname?: string;
  lastname?: string;
  emailaddress1?: string;
  telephone1?: string;
  vpi_city?: number;
  'vpi_city@OData.Community.Display.V1.FormattedValue'?: string;
  vpi_country?: string;
}

interface DataverseVehicleInfo {
  vpi_vehicledataid: string;
  vpi_make?: string;
  vpi_model?: string;
  vpi_year?: string;
  vpi_spec?: string;
  vpi_bodytype?: number;
  'vpi_bodytype@OData.Community.Display.V1.FormattedValue'?: string;
}

interface DataverseInquiryRow {
  vpi_vehicleinquiryid: string;
  _vpi_contact_value: string;
  _vpi_vehicle_value: string;
  vpi_status: number;
  'vpi_status@OData.Community.Display.V1.FormattedValue'?: string;
  createdon: string;
  'vpi_Contact': DataverseContactRow;
  'vpi_Vehicle': DataverseVehicleInfo;
}

interface ODataListResponse<T> {
  value: T[];
  '@odata.nextLink'?: string;
}

/* ─── Constants ──────────────────────────────────────── */

const BASE_CONTACTS = '/_api/contacts';
const BASE_INQUIRIES = '/_api/vpi_vehicleinquiries';

/** Shared headers needed for formatted values from option sets */
const ANNOTATIONS_HEADER: Record<string, string> = {
  Prefer: 'odata.include-annotations=*',
};

/** Expand clause used on every inquiry fetch */
const INQUIRY_EXPAND =
  "$expand=vpi_Contact($select=contactid,firstname,lastname,emailaddress1,telephone1,vpi_city,vpi_country),vpi_Vehicle($select=vpi_vehicledataid,vpi_make,vpi_model,vpi_year,vpi_spec,vpi_bodytype)";

/* ─── OData filter helpers ───────────────────────────── */

/** Escape a string for use inside an OData filter single-quoted literal. */
function odataEscape(value: string): string {
  return value.replace(/'/g, "''");
}

/* ─── Mappers ────────────────────────────────────────── */

/** Convert a Dataverse inquiry row to the application's Inquiry type. */
function toInquiry(row: DataverseInquiryRow): Inquiry {
  const contact = row['vpi_Contact'];
  const vehicle = row['vpi_Vehicle'];

  return {
    id: row.vpi_vehicleinquiryid,
    firstName: contact.firstname ?? '',
    lastName: contact.lastname ?? '',
    email: contact.emailaddress1 ?? '',
    phone: contact.telephone1 ?? '',
    country: contact.vpi_country ?? '',
    city:
      contact['vpi_city@OData.Community.Display.V1.FormattedValue'] ??
      '',
    consent: true,
    selectedVehicle: {
      year: parseInt(vehicle.vpi_year ?? '', 10) || 0,
      make: vehicle.vpi_make ?? '',
      model: vehicle.vpi_model ?? '',
      spec: vehicle.vpi_spec ?? '',
      bodyType:
        vehicle['vpi_bodytype@OData.Community.Display.V1.FormattedValue'] ??
        '',
    },
    createdAt: new Date(row.createdon),
    status: toInquiryStatus(row.vpi_status),
  };
}

/** Map a Dataverse numeric status value to the application enum (lowercase). */
function toInquiryStatus(numericValue: number): InquiryStatus {
  const label = inquiryStatusLabel(numericValue); // "Pending", "Reviewed", etc.
  return label.toLowerCase() as InquiryStatus;
}

/** Map the application status (lowercase) to the Dataverse numeric value. */
function toDataverseStatus(status: InquiryStatus): number {
  // Capitalise first letter: "pending" → "Pending"
  const label = status.charAt(0).toUpperCase() + status.slice(1);
  return inquiryStatusMapping[label] ?? 1; // default Pending
}

/* ─── Contact operations ─────────────────────────────── */

/**
 * Find a contact by email address.
 * Returns the contact row, or null if none exists.
 */
async function getContactByEmail(
  email: string,
): Promise<DataverseContactRow | null> {
  const escaped = odataEscape(email);
  const url = `${BASE_CONTACTS}?$select=contactid&$filter=emailaddress1 eq '${escaped}'`;

  const response = await dataverseAjax<ODataListResponse<DataverseContactRow>>(
    {
      type: 'GET',
      url,
      headers: { ...ANNOTATIONS_HEADER },
    },
  );

  return response.value.length > 0 ? (response.value[0] ?? null) : null;
}

/**
 * Create a new contact in Dataverse from the inquiry's personal info.
 * Returns the GUID of the newly created contact.
 */
async function createContact(inquiry: Inquiry): Promise<string> {
  const cityValue = cityMapping[inquiry.city];

  const payload: Record<string, unknown> = {
    firstname: inquiry.firstName,
    lastname: inquiry.lastName,
    emailaddress1: inquiry.email,
    telephone1: inquiry.phone,
    vpi_country: inquiry.country ?? 'UAE',
  };

  // Only set city if we have a valid mapping
  if (cityValue !== undefined) {
    payload.vpi_city = cityValue;
  }

  const created = await dataverseAjax<DataverseContactRow>({
    type: 'POST',
    url: BASE_CONTACTS,
    contentType: 'application/json',
    data: JSON.stringify(payload),
    headers: { ...ANNOTATIONS_HEADER },
  });

  return created.contactid;
}

/**
 * Find an existing contact by email, or create a new one.
 * Returns the contact GUID.
 */
async function findOrCreateContact(inquiry: Inquiry): Promise<string> {
  const existing = await getContactByEmail(inquiry.email);
  if (existing) {
    // Optionally update existing contact fields here if needed
    return existing.contactid;
  }
  return createContact(inquiry);
}

/* ─── Inquiry operations ─────────────────────────────── */

/**
 * Create a vehicle inquiry record linked to the given contact and vehicle.
 * Returns the GUID of the newly created inquiry.
 */
async function createInquiryRecord(
  contactId: string,
  vehicleId: string,
  status: InquiryStatus,
): Promise<string> {
  const dataverseStatus = toDataverseStatus(status);

  const payload = {
    'vpi_Contact@odata.bind': `/contacts(${contactId})`,
    'vpi_Vehicle@odata.bind': `/vpi_vehicledatas(${vehicleId})`,
    vpi_status: dataverseStatus,
  };

  const created = await dataverseAjax<DataverseInquiryRow>({
    type: 'POST',
    url: BASE_INQUIRIES,
    contentType: 'application/json',
    data: JSON.stringify(payload),
    headers: { ...ANNOTATIONS_HEADER },
  });

  return created.vpi_vehicleinquiryid;
}

/* ─── Public API ─────────────────────────────────────── */

export const inquiryService = {
  /**
   * Persist a full inquiry: create/find contact, then create inquiry record.
   *
   * @param inquiry  The inquiry data from the valuation wizard
   * @param vehicleId  Dataverse GUID of the selected vehicle
   * @returns  The Dataverse GUID of the newly created inquiry
   */
  async saveInquiry(
    inquiry: Inquiry,
    vehicleId: string,
  ): Promise<string> {
    const contactId = await findOrCreateContact(inquiry);
    const inquiryId = await createInquiryRecord(
      contactId,
      vehicleId,
      inquiry.status,
    );
    return inquiryId;
  },

  /**
   * Fetch all vehicle inquiries, newest first, with contact + vehicle data.
   */
  async getInquiries(): Promise<Inquiry[]> {
    const url = `${BASE_INQUIRIES}?${INQUIRY_EXPAND}&$orderby=createdon desc`;

    const response = await dataverseAjax<
      ODataListResponse<DataverseInquiryRow>
    >({
      type: 'GET',
      url,
      headers: { ...ANNOTATIONS_HEADER },
    });

    return (response.value ?? []).map(toInquiry);
  },

  /**
   * Fetch a single inquiry by its Dataverse GUID.
   */
  async getInquiryById(id: string): Promise<Inquiry | null> {
    const url = `${BASE_INQUIRIES}(${id})?${INQUIRY_EXPAND}`;

    try {
      const row = await dataverseAjax<DataverseInquiryRow>({
        type: 'GET',
        url,
        headers: { ...ANNOTATIONS_HEADER },
      });
      return toInquiry(row);
    } catch {
      return null;
    }
  },

  /**
   * Update the status of an inquiry.
   */
  async updateStatus(
    id: string,
    status: InquiryStatus,
  ): Promise<void> {
    const dataverseStatus = toDataverseStatus(status);

    await dataverseAjax<void>({
      type: 'PATCH',
      url: `${BASE_INQUIRIES}(${id})`,
      contentType: 'application/json',
      data: JSON.stringify({ vpi_status: dataverseStatus }),
    });
  },
};
